args.query:
WITH symbols AS (SELECT * FROM UNNEST(['AEFC','AIN','AIV','AIZP','AJRD','AL','AMN','AMP','AMT','ARD','ARGD','ARLO','ASG','AVA','BANC','BBU','BBVA','BDXA','BKH','BKT','BLD','BNS','BV','BZH','CADE','CAE','CAF','CBT','CCC','CCZ','CHAP','CIA','CMA','CMI','CMSA','CNK','COTY','CRC','CRM','CRS','CSL','CTS','CUBE','CURO','CVIA','CVX','CXH','DDT','DEO','DLTH','DNKN','DXC','EBS','EGO','EGY','EIG','ES','ESRT','EV','EXP','FCA','GCO','GD','GEL','GJP','GOGL','GOL','GPP','GT','GTY','H','HA','HBI','HEP','HNI','HRB','IHC','IQV','KAR','KBR','KDMN','KODK','KR','KRO','L','LAC','LIVN','LPI','LQ','LTC','LYV','MBT','MD','MDC','MEI','METC','MFC','MGA','MGF','MGM','MHK','MHO','MIK','MLP','MMS','MPA','MRO','MSM','MTD','MTW','MYE','MYOV','NBR','NC','NCLH','NFG','NGS','NHF','NIO','NJR','NMR','NOA','NOV','NRG','NRZ','NVGS','O','OEC','OII','OXY','PAC','PB','PBR','PCF','PCN','PCQ','PDM','PFN','PFO','PGP','PKG','PKI','PLL','PMO','PPR','PSTG','R','RA','RDY','RE','RES','RGR','RMD','RMG','RNP','ROK','RVP','RY','SAND','SB','SBS','SBSW','SCHW','SCI','SIX','SMM','SN','SPLP','SRC','SU','SVT','SXC','TAL','TBI','TEN','TGH','TGS','TNC','TRN','TRQ','TSE','UBS','UIS','UNM','USM','UVV','VFC','VIV','VKI','VNO','VRS','VVV','WBT','WCC','WES','WPC','WRE','WTR','XPO','YETI','ZIM'])
), counts AS (
  SELECT s.Symbol,
    (
      SELECT SUM(CASE WHEN Close>Open THEN 1 ELSE 0 END)
      FROM query_table(s.Symbol)
      WHERE Date>='2017-01-01' AND Date<='2017-12-31'
    ) AS up_days,
    (
      SELECT SUM(CASE WHEN Close<Open THEN 1 ELSE 0 END)
      FROM query_table(s.Symbol)
      WHERE Date>='2017-01-01' AND Date<='2017-12-31'
    ) AS down_days
  FROM symbols s
)
SELECT * FROM counts ORDER BY (up_days - down_days) DESC NULLS LAST LIMIT 5;

