args.query:
WITH syms AS (
  SELECT table_name AS Symbol
  FROM information_schema.tables
  WHERE table_schema='main' AND table_type='BASE TABLE'
), cnt AS (
  SELECT Symbol, COUNT(*) AS n2017
  FROM syms
  JOIN LATERAL (SELECT COUNT(*) AS n FROM query_table(Symbol) WHERE Date>='2017-01-01' AND Date<='2017-12-31') q ON TRUE
)
SELECT * FROM cnt ORDER BY n2017 DESC LIMIT 5;

